            marginBottom: 20,
            borderRadius: 4,
            background: msgType === 'error' ? '#FDEDEC' : '#E8F5E9',
            color: msgType === 'error' ? '#C0392B' : '#1E8449',
            border: `1px solid ${msgType === 'error' ? '#F1948A' : '#7DCEA0'}`
          }}>
            {msg}
          </div>
