                    </div>
                    <div className="dpm-field">
                      <label className="dpm-label">Sous-catégorie</label>
                      <select className="dpm-select" value={form.subCategory} onChange={(e) => setForm((f) => ({ ...f, subCategory: e.target.value }))}>
