                        {["Lips", "Face", "Eyes", "Foundation", "Skincare", "Serum", "Cleanser", "Moisturizer", "Mask", "Perfume", "Hair", "Body", "Soins", "Other"].map((sc) => (
                          <option key={sc} value={sc}>
                            {sc}
                          </option>
                        ))}
                      </select>
                    </div>
